1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
24	
25	#define AST_MAX 64
26	
27	// AST storage (parallel arrays)
28	int node_type[AST_MAX];
29	int node_val[AST_MAX];
30	int node_left[AST_MAX];
31	int node_right[AST_MAX];
32	int node_count;
33	
34	// Parser state
35	int parse_pos;
36	int parse_err;
37	char *parse_line;   // source line for identifier lookup
38	
39	// Allocate a new AST node
40	int ast_new() {
41	    if (node_count >= AST_MAX) {
42	        parse_err = 1;
43	        return 0;
44	    }
45	    int n = node_count;
46	    node_count++;
47	    node_left[n] = -1;
48	    node_right[n] = -1;
49	    return n;
50	}
51	
52	int ast_num(int val) {
53	    int n = ast_new();
54	    node_type[n] = NODE_NUM;
55	    node_val[n] = val;
56	    return n;
57	}
58	
59	int ast_binop(int op, int left, int right) {
60	    int n = ast_new();
61	    node_type[n] = NODE_BINOP;
62	    node_val[n] = op;
63	    node_left[n] = left;
64	    node_right[n] = right;
65	    return n;
66	}
67	
68	int ast_neg(int operand) {
69	    int n = ast_new();
70	    node_type[n] = NODE_NEG;
71	    node_right[n] = operand;
72	    return n;
73	}
74	
75	int ast_ident(int sym_idx) {
76	    int n = ast_new();
77	    node_type[n] = NODE_IDENT;
78	    node_val[n] = sym_idx;
79	    return n;
80	}
81	
82	int ast_assign(int sym_idx, int expr) {
83	    int n = ast_new();
84	    node_type[n] = NODE_ASSIGN;
