1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
12	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
13	int qled_shadow;
14	
15	// Apply a binary op to two scalars
16	int eval_binop_scalar(int op, int a, int b) {
17	    if (op == TOK_PLUS)       return a + b;
18	    if (op == TOK_MINUS)      return a - b;
19	    if (op == TOK_STAR)       return a * b;
20	    if (op == TOK_SLASH) {
21	        if (b == 0) { eval_err = 1; return 0; }
22	        return a / b;
23	    }
24	    eval_err = 1;
25	    return 0;
26	}
27	
28	// Evaluate AST node, return heap index of result array.
29	// On error, sets eval_err and returns -1.
30	int eval(int n) {
31	    if (eval_err) return -1;
32	    if (n < 0 || n >= node_count) {
33	        eval_err = 1;
34	        return -1;
35	    }
36	
37	    int ty = node_type[n];
38	
39	    if (ty == NODE_NUM) {
40	        int r = arr_scalar(node_val[n]);
41	        if (r < 0) { eval_err = 5; return -1; }
42	        return r;
43	    }
44	
45	    if (ty == NODE_VEC) {
46	        return node_val[n];
47	    }
48	
49	    if (ty == NODE_IDENT) {
50	        int idx = node_val[n];
51	        if (!sym_set_flag[idx]) {
52	            eval_err = 2;
53	            return -1;
54	        }
55	        return sym_val[idx];
56	    }
57	
58	    if (ty == NODE_ASSIGN) {
59	        int idx = node_val[n];
60	        int v = eval(node_right[n]);
61	        if (eval_err) return -1;
62	        sym_val[idx] = v;
63	        sym_set_flag[idx] = 1;
64	        return v;
65	    }
66	
67	    if (ty == NODE_QOUT) {
68	        int v = eval(node_right[n]);
69	        if (eval_err) return -1;
70	        return v;
71	    }
72	
73	    if (ty == NODE_QLED) {
74	        // Read LED D2 from shadow register (1=on, 0=off)
75	        int r = arr_scalar(qled_shadow);
76	        if (r < 0) { eval_err = 5; return -1; }
77	        return r;
78	    }
79	
80	    if (ty == NODE_QSW) {
81	        // Read switch S2: bit 0 of 0xFF0000, inverted (1=pressed, 0=released)
82	        int raw = *(char *)0xFF0000;
83	        int val = (raw ^ 1) & 1;
84	        int r = arr_scalar(val);
85	        if (r < 0) { eval_err = 5; return -1; }
86	        return r;
87	    }
88	
89	    if (ty == NODE_QLED_ASSIGN) {
90	        int v = eval(node_right[n]);
91	        if (eval_err) return -1;
92	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
93	        int val = arr_get(v, 0) & 1;
94	        qled_shadow = val;
95	        // Write LED D2: invert bit 0 (active-low: 1=on writes 0)
96	        *(char *)0xFF0000 = val ^ 1;
97	        return v;
98	    }
99	
100	    if (ty == NODE_QSVO) {
101	        // Shared variable offer: IDENT qsvo AP
102	        // Evaluate AP number, couple symbol if AP supported
103	        int v = eval(node_right[n]);
104	        if (eval_err) return -1;
105	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
106	        int ap = arr_get(v, 0);
107	        int sym_idx = node_val[n];
108	        if (ap == 242) {
109	            // AP 242: MMIO byte access (FF0000+offset)
110	            svo_ap[sym_idx] = 242;
111	            int r = arr_scalar(2);
112	            if (r < 0) { eval_err = 5; return -1; }
113	            return r;
114	        }
115	        // Unknown AP: return 0 (not coupled)
116	        svo_ap[sym_idx] = 0;
117	        int r = arr_scalar(0);
118	        if (r < 0) { eval_err = 5; return -1; }
119	        return r;
120	    }
121	
122	    if (ty == NODE_NEG) {
123	        int v = eval(node_right[n]);
124	        if (eval_err) return -1;
125	        int rk = arr_rank(v);
126	        if (rk == 0) {
127	            int r = arr_scalar(0 - arr_get(v, 0));
128	            if (r < 0) { eval_err = 5; return -1; }
129	            return r;
130	        }
131	        // Negate each element of vector
132	        if (rk == 1) {
133	            int sz = arr_size(v);
134	            int r = arr_vector(sz);
135	            if (r < 0) { eval_err = 5; return -1; }
136	            int i = 0;
137	            while (i < sz) {
138	                arr_set(r, i, 0 - arr_get(v, i));
139	                i++;
140	            }
141	            return r;
142	        }
143	        // Negate each element of matrix
144	        if (rk == 2) {
145	            int d0 = arr_dim0(v);
146	            int d1 = arr_dim1(v);
147	            int sz = d0 * d1;
148	            int r = arr_new(2, d0, d1);
149	            if (r < 0) { eval_err = 5; return -1; }
150	            int i = 0;
151	            while (i < sz) {
152	                arr_set(r, i, 0 - arr_get(v, i));
153	                i++;
154	            }
155	            return r;
156	        }
157	        eval_err = 4;
158	        return -1;
159	    }
160	
161	    if (ty == NODE_MONAD) {
162	        int v = eval(node_right[n]);
163	        if (eval_err) return -1;
164	        int res_id = node_val[n];
165	
166	        if (res_id == RES_IOTA) {
167	            // iota N: generate vector 0 1 2 ... N-1
168	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
169	            int count = arr_get(v, 0);
170	            if (count < 0) { eval_err = 1; return -1; }
171	            int r = arr_vector(count);
172	            if (r < 0) { eval_err = 5; return -1; }
173	            int i = 0;
174	            while (i < count) {
175	                arr_set(r, i, i);
176	                i++;
177	            }
178	            return r;
179	        }
180	
181	        if (res_id == RES_RHO) {
182	            // rho A: return shape of A
183	            int rk = arr_rank(v);
184	            if (rk == 0) {
185	                // Scalar: shape is empty vector
186	                int r = arr_vector(0);
187	                if (r < 0) { eval_err = 5; return -1; }
188	                return r;
189	            }
190	            if (rk == 1) {
191	                // Vector: shape is 1-element vector with length
192	                int r = arr_scalar(arr_dim0(v));
193	                if (r < 0) { eval_err = 5; return -1; }
194	                return r;
195	            }
196	            if (rk == 2) {
197	                // Matrix: shape is 2-element vector (rows cols)
198	                int r = arr_vector(2);
199	                if (r < 0) { eval_err = 5; return -1; }
200	                arr_set(r, 0, arr_dim0(v));
201	                arr_set(r, 1, arr_dim1(v));
202	                return r;
203	            }
204	            eval_err = 4;
205	            return -1;
206	        }
207	
208	        if (res_id == RES_REV) {
209	            // rev A: reverse a vector
210	            int rk = arr_rank(v);
211	            if (rk == 0) {
212	                // Scalar: reverse is identity
213	                return v;
214	            }
215	            if (rk == 1) {
216	                int sz = arr_size(v);
217	                int r = arr_vector(sz);
218	                if (r < 0) { eval_err = 5; return -1; }
219	                int i = 0;
220	                while (i < sz) {
221	                    arr_set(r, i, arr_get(v, sz - 1 - i));
222	                    i++;
223	                }
224	                return r;
225	            }
226	            eval_err = 4;
227	            return -1;
228	        }
229	
230	        if (res_id == RES_CAT) {
231	            // Monadic cat: ravel (flatten to 1D vector)
232	            int rk = arr_rank(v);
233	            if (rk == 0) {
234	                // Scalar -> 1-element vector
235	                int r = arr_vector(1);
236	                if (r < 0) { eval_err = 5; return -1; }
237	                arr_set(r, 0, arr_get(v, 0));
238	                return r;
239	            }
240	            if (rk == 1) {
241	                // Vector: already 1D, return as-is
242	                return v;
243	            }
244	            if (rk == 2) {
245	                // Matrix -> vector of all elements
246	                int sz = arr_size(v);
247	                int r = arr_vector(sz);
248	                if (r < 0) { eval_err = 5; return -1; }
249	                int i = 0;
250	                while (i < sz) {
251	                    arr_set(r, i, arr_get(v, i));
252	                    i++;
253	                }
254	                return r;
255	            }
256	            eval_err = 4;
257	            return -1;
258	        }
259	
260	        // Unknown monadic function
261	        eval_err = 1;
262	        return -1;
263	    }
264	
265	    if (ty == NODE_REDUCE) {
266	        int v = eval(node_right[n]);
267	        if (eval_err) return -1;
268	        int op = node_val[n];
269	        int rk = arr_rank(v);
270	
271	        // Scalar reduce: just return the scalar
272	        if (rk == 0) {
273	            return v;
274	        }
275	
276	        // Vector reduce: right-to-left fold
277	        if (rk == 1) {
278	            int sz = arr_size(v);
279	            if (sz == 0) {
280	                // Empty vector: return identity element
281	                int id;
282	                if (op == TOK_PLUS || op == TOK_MINUS) id = 0;
283	                else if (op == TOK_STAR || op == TOK_SLASH) id = 1;
284	                else { eval_err = 1; return -1; }
285	                int r = arr_scalar(id);
286	                if (r < 0) { eval_err = 5; return -1; }
287	                return r;
288	            }
289	            int acc = arr_get(v, sz - 1);
290	            int i = sz - 2;
291	            while (i >= 0) {
292	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
293	                if (eval_err) return -1;
294	                i--;
295	            }
296	            int r = arr_scalar(acc);
297	            if (r < 0) { eval_err = 5; return -1; }
298	            return r;
299	        }
300	
301	        // Unsupported rank for reduce
302	        eval_err = 4;
303	        return -1;
304	    }
