317	            int lrk = arr_rank(lv);
318	            int new_rank;
319	            int d0;
320	            int d1;
321	
322	            if (lrk == 0) {
323	                // Scalar shape -> vector
324	                new_rank = 1;
325	                d0 = arr_get(lv, 0);
326	                d1 = 0;
327	                if (d0 < 0) { eval_err = 1; return -1; }
328	            } else if (lrk == 1) {
329	                int lsz = arr_size(lv);
330	                if (lsz == 1) {
331	                    new_rank = 1;
332	                    d0 = arr_get(lv, 0);
333	                    d1 = 0;
334	                    if (d0 < 0) { eval_err = 1; return -1; }
335	                } else if (lsz == 2) {
336	                    new_rank = 2;
337	                    d0 = arr_get(lv, 0);
338	                    d1 = arr_get(lv, 1);
339	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
340	                } else {
341	                    // Only rank 1 and 2 supported
342	                    eval_err = 4;
343	                    return -1;
344	                }
345	            } else {
346	                eval_err = 4;
347	                return -1;
348	            }
349	
350	            int r = arr_new(new_rank, d0, d1);
351	            if (r < 0) { eval_err = 5; return -1; }
352	
353	            int total = arr_size(r);
354	            int src_sz = arr_size(rv);
355	            if (src_sz == 0) { eval_err = 3; return -1; }
356	
357	            int i = 0;
358	            while (i < total) {
359	                arr_set(r, i, arr_get(rv, i % src_sz));
360	                i++;
361	            }
362	            return r;
363	        }
364	
365	        if (res_id == RES_TAKE) {
366	            // N take A: take first N elements/rows (negative N = from end)
367	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
368	            int count = arr_get(lv, 0);
369	            int rrk = arr_rank(rv);
370	
371	            if (rrk <= 1) {
372	                int sz = arr_size(rv);
373	                int abs_n = count;
374	                if (abs_n < 0) abs_n = 0 - abs_n;
375	                if (abs_n > sz) { eval_err = 3; return -1; }
376	
377	                int r = arr_vector(abs_n);
378	                if (r < 0) { eval_err = 5; return -1; }
379	                int start = 0;
380	                if (count < 0) start = sz - abs_n;
381	                int i = 0;
382	                while (i < abs_n) {
383	                    arr_set(r, i, arr_get(rv, start + i));
384	                    i++;
385	                }
386	                return r;
387	            }
388	
389	            if (rrk == 2) {
390	                int rows = arr_dim0(rv);
391	                int cols = arr_dim1(rv);
392	                int abs_n = count;
393	                if (abs_n < 0) abs_n = 0 - abs_n;
