395	
396	                int r = arr_new(2, abs_n, cols);
397	                if (r < 0) { eval_err = 5; return -1; }
398	                int start_row = 0;
399	                if (count < 0) start_row = rows - abs_n;
400	                int total = abs_n * cols;
