413	        if (res_id == RES_DROP) {
414	            // N drop A: drop first N elements/rows (negative N = from end)
415	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
416	            int count = arr_get(lv, 0);
417	            int rrk = arr_rank(rv);
