476	            }
477	            i = 0;
478	            while (i < rsz) {
479	                arr_set(r, lsz + i, arr_get(rv, i));
480	                i++;
481	            }
482	            return r;
483	        }
484	
485	        // Unknown dyadic function
486	        eval_err = 1;
487	        return -1;
488	    }
489	
490	    if (ty == NODE_BINOP) {
491	        int lv = eval(node_left[n]);
492	        if (eval_err) return -1;
493	        int rv = eval(node_right[n]);
494	        if (eval_err) return -1;
