1	// COR24 APL Interpreter -- main entry point
2	// Phase 6: shared variable I/O (qled, qsw, qsvo)
3	
4	#include <stdio.h>
5	#include "io.h"
6	#include "num.h"
7	#include "arr.h"
8	#include "tok.h"
9	#include "sym.h"
10	#include "parse.h"
11	#include "eval.h"
12	
13	int main() {
14	    char line[IO_LINE_MAX];
15	
16	    arr_reset();
17	    puts("COR24 APL v0.1");
18	
19	    while (1) {
20	        io_print("      ");
21	        int n = io_getline(line, IO_LINE_MAX);
22	        if (n == 0) {
23	            // Empty line -- just re-prompt
24	        } else if (line[0] == 41) {
25	            // System command: starts with ')'
26	            if (str_match(line, 1, "CLEAR") == 5 && (line[6] == 0 || line[6] == 32)) {
27	                arr_reset();
28	                sym_reset();
29	                io_print("  CLEAR WS");
30	                putchar(10);
31	            } else if (str_match(line, 1, "VARS") == 4 && (line[5] == 0 || line[5] == 32)) {
32	                int i = 0;
33	                int any = 0;
34	                while (i < sym_count) {
35	                    if (sym_set_flag[i]) {
36	                        if (any) io_print("  ");
37	                        int off = sym_name_off[i];
38	                        while (sym_name_buf[off]) {
39	                            putchar(sym_name_buf[off]);
40	                            off++;
41	                        }
42	                        any = 1;
43	                    }
44	                    i++;
